import ast
import operator

class SafeEvaluator:
    def __init__(self):
        self.ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

    def visit(self, node):
        if isinstance(node, ast.Expression):
            return self.visit(node.body)
        if isinstance(node, ast.Num):
            return node.n
        if isinstance(node, ast.BinOp):
            left = self.visit(node.left)
            right = self.visit(node.right)
            op = type(node.op)
            if op in self.ops:
                return self.ops[op](left, right)
            else:
                raise ValueError("Invalid operation")
        if isinstance(node, ast.UnaryOp):
            operand = self.visit(node.operand)
            op = type(node.op)
            if op in self.ops:
                return self.ops[op](operand)
            else:
                raise ValueError("Invalid operation")
        raise ValueError("Invalid node type")

def evaluate_expression(expr: str) -> str:
    try:
        tree = ast.parse(expr, mode='eval')
        evaluator = SafeEvaluator()
        result = evaluator.visit(tree)
        return str(result)
    except:
        return ""

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    if info_type not in {'lang', 'encoding', 'cache'}:
        return header
    new_header = header.copy()
    if info_type == 'lang':
        new_header['Accept-Language'] = info_content
    elif info_type == 'encoding':
        new_header['Accept-Encoding'] = info_content
    else:
        new_header['Cache-Control'] = info_content
    return new_header

