import ast
import sys
import io

app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    code = request.args.get('code')
    if not code:
        return "No code provided", 400

    try:
        tree = ast.parse(code)
        if not tree.body:
            return "Empty code", 400

        # Check for dangerous operations
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom, ast.Call, ast.Assign)):
                if isinstance(node, ast.Import) or isinstance(node, ast.ImportFrom):
                    for name in node.names:
                        if name.name in ('os', 'sys', 'subprocess', 'webbrowser', 'socket', 'http', 'urllib', 'requests'):
                            return "Forbidden module", 403
                elif isinstance(node, ast.Call):
                    if isinstance(node.func, ast.Name) and node.func.id in ('eval', 'exec', 'compile'):
                        return "Forbidden function", 403
                elif isinstance(node, ast.Assign):
                    for target in node.targets:
                        if isinstance(target, ast.Name) and target.id in ('__builtins__', '__import__'):
                            return "Forbidden variable", 403
        # Execute in a restricted environment
        old_stdout = sys.stdout
        sys.stdout = io.StringIO()
        try:
            exec(code, {'__builtins__': None}, {})
        except Exception as e:
            return f"Error: {str(e)}", 500
        finally:
            sys.stdout = old_stdout
        return "Executed", 200
    except SyntaxError:
        return "Invalid syntax", 400
    except Exception as e:
        return f"Error: {str(e)}", 500

