import re

def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[0-9]', password):
        return False
    if not re.search(r'[!@#$%^&*]', password):
        return False
    if re.search(r'\s', password):
        return False
    weak_passwords = {'password', '123456', 'admin', '123456789', 'qwerty'}
    if password in weak_passwords:
        return False
    return True

